module calendar(
    input CLK,
    input RST,
    output [5:0] Hours,
    output [5:0] Mins,
    output [5:0] Secs
);

reg [5:0] sec, min, hour;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        sec <= 0;
        min <= 0;
        hour <= 0;
    end
    else begin
        sec <= sec + 1;
        if (sec == 59) begin
            sec <= 0;
            min <= min + 1;
            if (min == 59) begin
                min <= 0;
                hour <= hour + 1;
                if (hour == 23) begin
                    hour <= 0;
                end
            end
        end
    end
end

assign Hours = hour;
assign Mins = min;
assign Secs = sec;

endmodule
